html.script:
/**
 * QUnit Test Runner for Whitelist Manager
 *
 * Loads QUnit library and all test files, runs tests, and displays results.
 */
(function() {
  "use strict";

  var statusElement = document.getElementById("qunit");
  statusElement.textContent = "Loading QUnit Test Runner...";

  // Load QUnit script
  var qunitScript = document.createElement("script");
  qunitScript.src = "https://code.jquery.com/qunit/qunit-2.19.4.js";
  qunitScript.onload = function() {
    if (typeof QUnit !== "undefined") {
      console.log("QUnit library loaded successfully");

      // Configure QUnit
      QUnit.config.autostart = false;
      QUnit.config.hidepassed = false;

      // Load Splunk dependencies and test files
      require([
        "jquery",
        "underscore",
        "splunkjs/mvc"
      ], function($, _, mvc) {
        console.log("Splunk dependencies loaded");

        var testFiles = [
          "../../app/wl_manager/tests/qunit/test_state_manager.js",
          "../../app/wl_manager/tests/qunit/test_rest_helpers.js",
          "../../app/wl_manager/tests/qunit/test_module_loading.js",
          "../../app/wl_manager/tests/qunit/test_state_transitions.js",
          "../../app/wl_manager/appserver/static/tests/test_wl_cp_queue.js",
          "../../app/wl_manager/appserver/static/tests/test_wl_cp_limits.js",
          "../../app/wl_manager/appserver/static/tests/test_wl_cp_trash.js",
          "../../app/wl_manager/appserver/static/tests/test_wl_cp_usage.js",
          "../../app/wl_manager/appserver/static/tests/test_wl_cp_admin_limits.js"
        ];

        var filesLoaded = 0;
        var fileLoadErrors = [];

        function loadNextTest() {
          if (filesLoaded >= testFiles.length) {
            console.log("All test files processed, starting QUnit");
            QUnit.start();
            return;
          }

          var testFile = testFiles[filesLoaded];
          var script = document.createElement("script");
          script.src = testFile + "?" + new Date().getTime();
          script.async = true;
          script.onload = function() {
            filesLoaded++;
            console.log("Loaded test file: " + testFile);
            loadNextTest();
          };
          script.onerror = function() {
            fileLoadErrors.push(testFile);
            filesLoaded++;
            console.warn("Failed to load: " + testFile);
            loadNextTest();
          };
          document.head.appendChild(script);
        }

        loadNextTest();
      });
    } else {
      statusElement.textContent = "Failed to load QUnit library";
      console.error("QUnit library failed to load");
    }
  };

  qunitScript.onerror = function() {
    statusElement.textContent = "Failed to load QUnit from CDN";
    console.error("Failed to load QUnit script");
  };

  document.head.appendChild(qunitScript);
})();
